def demo(*args, **kwargs):
    print(args)    # (1, 2, 3)
    print(kwargs)  # {'x': 10}
demo(1, 2, 3, x=10)

def log_call(func):
    def wrapper(*args, **kwargs):
        print(f"Calling {func.__name__}")
        return func(*args, **kwargs)
    return wrapper

@log_call
def greet(name):
    print(f"Hello, {name}")

def count_up_to(n):
    i = 1
    while i <= n:
        yield i
        i += 1
for num in count_up_to(3):
    print(num)  # 1 2 3

class Pizza:
    def __init__(self, size):
        self.size = size
    @classmethod
    def small(cls):
        return cls(size='small')
    @staticmethod
    def is_valid_size(size):
        return size in ['small', 'medium', 'large']

